// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// Try OpenWeather tiles first (fast if API key ok); on error auto-fallback to RainViewer latest frame
const OWM_KEY = process.env.REACT_APP_OWM_KEY || import.meta?.env?.VITE_OWM_KEY;
const DEFAULT_CENTER = [33.749, -84.388];
const DEFAULT_ZOOM = 6;

export default function Radar() {
  const mapRef = useRef(null);
  const layerRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [provider, setProvider] = useState(OWM_KEY ? "owm" : "rainviewer");
  const [errorText, setErrorText] = useState("");

  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView(DEFAULT_CENTER, DEFAULT_ZOOM);

    L.tileLayer(
      "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
      { subdomains: "abcd", maxZoom: 18, opacity: 0.95 }
    ).addTo(map);

    mapRef.current = map;
    setTimeout(() => map.invalidateSize(), 0); // ensure proper sizing
  }, []);

  // Render the chosen provider
  useEffect(() => {
    const map = mapRef.current;
    if (!map) return;

    // helper to replace layer
    const setLayer = (newLayer) => {
      if (layerRef.current) map.removeLayer(layerRef.current);
      layerRef.current = newLayer.addTo(map);
    };

    let cancel = false;
    const loadOWM = async () => {
      if (!OWM_KEY) throw new Error("Missing OWM key");
      setLoading(true);
      setErrorText("");

      const precip = L.tileLayer(
        `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`,
        { opacity: 0.85, zIndex: 500, crossOrigin: true }
      )
        .on("load", () => !cancel && setLoading(false))
        .on("tileerror", () => {
          if (!cancel) throw new Error("OWM tiles failed");
        });

      setLayer(precip);
    };

    const loadRainViewer = async () => {
      setLoading(true);
      setErrorText("");

      try {
        const meta = await fetch("https://api.rainviewer.com/public/weather-maps.json").then(r => r.json());
        const host = meta?.host || "";
        const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
        const last = frames.at(-1)?.time;
        if (!host || !last) throw new Error("No RainViewer frames");
        const layer = L.tileLayer(`${host}/v2/radar/${last}/256/{z}/{x}/{y}.png`, {
          opacity: 0.85, zIndex: 500, crossOrigin: true
        })
          .on("load", () => !cancel && setLoading(false))
          .on("tileerror", () => !cancel && setErrorText("RainViewer tiles are unavailable right now."));
        setLayer(layer);
      } catch (e) {
        if (!cancel) {
          setErrorText("Radar data unavailable.");
          setLoading(false);
        }
      }
    };

    (async () => {
      try {
        if (provider === "owm") {
          await loadOWM();
        } else {
          await loadRainViewer();
        }
      } catch (e) {
        // automatic fallback: if OWM fails, try RainViewer once
        if (provider === "owm") {
          setProvider("rainviewer");
        } else {
          setErrorText(e?.message || "Radar failed to load.");
          setLoading(false);
        }
      }
    })();

    return () => { cancel = true; };
  }, [provider]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">Radar</div>
        <div className="flex items-center gap-2 text-xs">
          <span className={`px-2 py-0.5 rounded ${provider === "owm" ? "bg-white/20" : "bg-white/10"}`}>OWM</span>
          <span className={`px-2 py-0.5 rounded ${provider === "rainviewer" ? "bg-white/20" : "bg-white/10"}`}>RV</span>
        </div>
      </div>

      <div id="radar-map" className="w-full" style={{ height: 320 }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-t-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}

      <div className="absolute bottom-3 left-3 text-[11px] rounded bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy (red)
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snow
        </div>
      </div>
    </div>
  );
}
